import subprocess
import sys
import shutil
import os

def install_dependencies():
    """Installs project dependencies from requirements.txt."""
    print("Installing dependencies from requirements.txt...")
    try:
        subprocess.run([sys.executable, "-m", "pip", "install", "-r", "requirements.txt"], check=True)
        print("Dependencies installed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Error installing dependencies: {e}")
        sys.exit(1)

def run_tests():
    """Runs application tests."""
    print("Running application tests...")
    try:
        # Assuming pytest is used for tests. Adjust command if using unittest, nose, etc.
        subprocess.run([sys.executable, "-m", "pytest"], check=True)
        print("Tests passed successfully.")
    except subprocess.CalledProcessError as e:
        print(f"Tests failed: {e}")
        sys.exit(1)

def package_application(output_dir="dist"):
    """Packages the application for deployment."""
    print(f"Packaging application for deployment into '{output_dir}'...")

    if os.path.exists(output_dir):
        shutil.rmtree(output_dir)
    os.makedirs(output_dir)

    # Example: Copying relevant files to the deployment package directory
    # Adjust this list based on what your application needs to run.
    # This might include source code, configuration files, static assets, templates, etc.
    files_to_copy = [
        "app.py",  # Main application entry point
        "requirements.txt",
        "pyproject.toml", # If using poetry/setuptools build
        "README.md",
        # Add directories or specific files your app needs
        # e.g., "src/", "config/", "static/", "templates/"
    ]

    # Simple example: copy individual files.
    # For more complex projects, consider using 'shutil.copytree' for directories
    # or a build tool like setuptools/flit/poetry to create a wheel/sdist.
    for item in files_to_copy:
        if os.path.exists(item):
            if os.path.isfile(item):
                shutil.copy(item, os.path.join(output_dir, os.path.basename(item)))
                print(f"  Copied file: {item}")
            elif os.path.isdir(item):
                # Copy entire directories
                dest_path = os.path.join(output_dir, os.path.basename(item))
                shutil.copytree(item, dest_path)
                print(f"  Copied directory: {item}")
        else:
            print(f"  Warning: Item '{item}' not found, skipping.")

    # A more robust packaging strategy for Python applications
    # would involve building a wheel or source distribution.
    # For example, using setuptools:
    try:
        print("Attempting to build a Python wheel (if setup.py/pyproject.toml exists)...")
        subprocess.run([sys.executable, "-m", "pip", "install", "build"], check=True, capture_output=True)
        subprocess.run([sys.executable, "-m", "build", "--wheel", "--outdir", output_dir, "."], check=True)
        print(f"Python wheel built successfully into '{output_dir}'.")
    except (subprocess.CalledProcessError, FileNotFoundError) as e:
        print(f"Could not build Python wheel (is setup.py or pyproject.toml configured?): {e}")
        print("Proceeding with simple file copy packaging.")

    print(f"Application packaged successfully into '{output_dir}'.")

def main():
    print("Starting deployment automation script...")
    install_dependencies()
    run_tests()
    package_application()
    print("Deployment automation script finished successfully.")

if __name__ == "__main__":
    main()